import { useEffect, useRef } from 'react'
import type { Contact, Template } from '../../types'
import { drawVerticalBlock } from '../../lib/verticalText'

/** 1mm あたりのピクセル数 (96 dpi 基準) */
const MM_TO_PX = 96 / 25.4 // ≈ 3.78

/**
 * デフォルトテンプレート: A4 12面ラベル (86.4×42.3mm)
 * テンプレート選択 UI が実装されるまでのフォールバック用。
 */
export const DEFAULT_TEMPLATE: Template = {
  id: 'default-a4-12',
  name: '標準 (A4 12面)',
  orientation: 'vertical',
  labelWidth: 86.4,
  labelHeight: 42.3,
  postalCode: {
    x: 36,        // 〒マーク左端 (mm)
    y: 4.5,       // 上端からの距離 (mm)
    digitSpacing: 5.5,
    fontSize: 10,
  },
  recipient: {
    nameX: 79,    // 氏名カラム右端 (mm)
    nameY: 8,     // 上端からの距離 (mm)
    nameFont: 13,
    addressX: 69, // 住所ブロック右端 (mm)
    addressY: 8,  // 上端からの距離 (mm)
    addressFont: 8.5,
  },
  sender: {
    nameX: 16,    // 差出人氏名カラム右端 (mm)
    nameY: 24,
    nameFont: 6.5,
    addressX: 8,  // 差出人住所ブロック右端 (mm)
    addressY: 24,
    addressFont: 5.5,
  },
}

/** 郵便番号を "NNN-NNNN" 形式に整形する */
function formatPostalCode(raw: string): string {
  const digits = raw.replace(/\D/g, '')
  if (digits.length === 7) return `${digits.slice(0, 3)}-${digits.slice(3)}`
  return raw
}

/** px 変換ヘルパー */
function mm(value: number, scale: number): number {
  return value * MM_TO_PX * scale
}

interface LabelCanvasProps {
  contact: Contact
  template?: Template
  /** 表示倍率 (デフォルト 1.0) */
  zoom?: number
}

export default function LabelCanvas({
  contact,
  template = DEFAULT_TEMPLATE,
  zoom = 1,
}: LabelCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  const canvasW = Math.round(mm(template.labelWidth, zoom))
  const canvasH = Math.round(mm(template.labelHeight, zoom))

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    // デバイスピクセル比を考慮した高解像度レンダリング
    const dpr = window.devicePixelRatio || 1
    canvas.width = canvasW * dpr
    canvas.height = canvasH * dpr
    canvas.style.width = `${canvasW}px`
    canvas.style.height = `${canvasH}px`
    ctx.scale(dpr, dpr)

    renderLabel(ctx, contact, template, zoom)
  }, [contact, template, zoom, canvasW, canvasH])

  return (
    <canvas
      ref={canvasRef}
      style={{ width: canvasW, height: canvasH }}
      className="shadow-sm"
    />
  )
}

function renderLabel(
  ctx: CanvasRenderingContext2D,
  contact: Contact,
  tpl: Template,
  zoom: number,
): void {
  const s = zoom // スケール係数 (zoom のみ。MM_TO_PX は mm() 内で適用済み)
  const W = mm(tpl.labelWidth, s)
  const H = mm(tpl.labelHeight, s)

  // ─── 背景 ───────────────────────────────────────────────
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, W, H)

  // ─── 外枠 ───────────────────────────────────────────────
  ctx.strokeStyle = '#d1d5db'
  ctx.lineWidth = 0.5
  ctx.strokeRect(0.5, 0.5, W - 1, H - 1)

  // ─── 郵便番号 ────────────────────────────────────────────
  if (tpl.postalCode && contact.postalCode) {
    const pc = tpl.postalCode
    const fontSize = mm(pc.fontSize / 2.835, s) // pt → mm → px (1pt≈0.353mm)
    const spacing = mm(pc.digitSpacing, s)
    const startX = mm(pc.x, s)
    const baseY = mm(pc.y, s)

    ctx.fillStyle = '#111827'
    ctx.font = `${fontSize}px "Hiragino Kaku Gothic ProN", "Meiryo", sans-serif`
    ctx.textAlign = 'left'
    ctx.textBaseline = 'top'

    // 〒マーク
    ctx.fillText('〒', startX - spacing * 0.3, baseY)

    const digits = contact.postalCode.replace(/\D/g, '')
    const formatted = formatPostalCode(digits)
    // ハイフン込みで1文字ずつ等間隔に描画
    let ox = startX + spacing * 0.5
    for (const ch of formatted) {
      ctx.fillText(ch, ox, baseY)
      ox += ch === '-' ? spacing * 0.5 : spacing
    }
  }

  // ─── 宛先 氏名 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const nameFontPx = mm(rc.nameFont / 2.835, s)
    const name = `${contact.familyName}${contact.givenName}`
    const honorific = contact.honorific || '様'

    ctx.fillStyle = '#111827'
    ctx.font = `${nameFontPx}px "Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif`

    // 氏名: 右端カラム、敬称は独立した右隣カラム
    drawVerticalBlock({
      ctx,
      lines: [honorific, name],
      rightX: mm(rc.nameX, s),
      topY: mm(rc.nameY, s),
      fontSize: nameFontPx,
      convertNumbers: false,
    })
  }

  // ─── 宛先 住所 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const addrFontPx = mm(rc.addressFont / 2.835, s)

    // 住所を2列に分割: 都道府県+市区町村 / 番地+建物名
    const addrLine1 = `${contact.prefecture}${contact.city}`
    const addrLine2 = `${contact.street}${contact.building ? `　${contact.building}` : ''}`

    ctx.fillStyle = '#111827'
    ctx.font = `${addrFontPx}px "Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif`

    drawVerticalBlock({
      ctx,
      lines: [addrLine1, addrLine2].filter(Boolean),
      rightX: mm(rc.addressX, s),
      topY: mm(rc.addressY, s),
      fontSize: addrFontPx,
      convertNumbers: true,
    })
  }

  // ─── 差出人（会社名があれば部署・会社を優先） ──────────────
  const senderName = contact.company
    ? `${contact.company}${contact.department ? `　${contact.department}` : ''}`
    : null

  // 差出人エリアは将来 Sender エンティティで置き換える
  // (Phase 6: 差出人管理) — 現状は連絡先の会社情報をダミーで表示しない
  // 仕様: 差出人は別エンティティなので、ここでは表示領域の余白のみ確保
  void senderName // 未使用警告抑制
}

import { create } from 'zustand'
import type { Watermark, QRConfig } from '../types'

interface DecorationState {
  watermark: Watermark | null
  qrConfig: QRConfig
  setWatermark: (watermark: Watermark | null) => void
  setQRConfig: (config: Partial<QRConfig>) => void
}

const defaultQRConfig: QRConfig = {
  enabled: false,
  content: '',
  size: 40,
  position: 'bottom-right',
}

export const useDecorationStore = create<DecorationState>((set, get) => ({
  watermark: null,
  qrConfig: defaultQRConfig,
  setWatermark: (watermark) => set({ watermark }),
  setQRConfig: (config) => set({ qrConfig: { ...get().qrConfig, ...config } }),
}))

import { useState } from 'react'
import type { View } from './types'
import ContactList from './components/address/ContactList'
import LabelCanvas, { DEFAULT_TEMPLATE } from './components/preview/LabelCanvas'
import { useShallow } from 'zustand/shallow'
import { useContactStore } from './stores/contactStore'

function App() {
  const [view, setView] = useState<View>('contacts')
  const { contacts, selectedIds } = useContactStore(
    useShallow((s) => ({ contacts: s.contacts, selectedIds: s.selectedIds })),
  )

  // プレビュー対象: 選択中の最初の連絡先
  const previewContact = contacts.find((c) => selectedIds.has(c.id)) ?? null

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900">
      {/* サイドバー */}
      <nav className="w-48 bg-white border-r border-gray-200 flex flex-col p-3 gap-1 shrink-0">
        <h1 className="text-sm font-bold px-2 py-3 text-gray-700">Atena ラベル印刷</h1>
        <NavButton active={view === 'contacts'} onClick={() => setView('contacts')}>
          住所録
        </NavButton>
        <NavButton active={view === 'preview'} onClick={() => setView('preview')}>
          ラベルプレビュー
        </NavButton>
        <NavButton active={view === 'settings'} onClick={() => setView('settings')}>
          設定
        </NavButton>
      </nav>

      {/* メインコンテンツ */}
      <main className="flex-1 flex overflow-hidden">
        {view === 'contacts' && (
          <div className="w-72 border-r border-gray-200 bg-white flex flex-col h-full">
            <ContactList />
          </div>
        )}
        {view === 'contacts' && (
          <div className="flex-1 flex items-center justify-center bg-[#f0f0f0]">
            {previewContact ? (
              <div className="flex flex-col items-center gap-3">
                <p className="text-xs text-gray-500">ラベルプレビュー</p>
                <LabelCanvas contact={previewContact} template={DEFAULT_TEMPLATE} zoom={2} />
              </div>
            ) : (
              <p className="text-gray-400 text-sm">連絡先を選択するとプレビューが表示されます</p>
            )}
          </div>
        )}
        {view === 'preview' && (
          <div className="flex-1 flex items-center justify-center bg-[#f0f0f0] p-6">
            {previewContact ? (
              <div className="flex flex-col items-center gap-3">
                <p className="text-xs text-gray-500">
                  {previewContact.familyName} {previewContact.givenName} — {DEFAULT_TEMPLATE.name}
                </p>
                <LabelCanvas contact={previewContact} template={DEFAULT_TEMPLATE} zoom={3} />
              </div>
            ) : (
              <p className="text-gray-400 text-sm">住所録から連絡先を選択してください</p>
            )}
          </div>
        )}
        {view === 'settings' && (
          <div className="flex-1 p-6">
            <h2 className="text-xl font-semibold mb-4">設定</h2>
            <p className="text-gray-500">Phase 6 で実装予定</p>
          </div>
        )}
      </main>
    </div>
  )
}

function NavButton({
  active,
  onClick,
  children,
}: {
  active: boolean
  onClick: () => void
  children: React.ReactNode
}) {
  return (
    <button
      onClick={onClick}
      className={`text-left px-3 py-2 rounded-md text-sm transition-colors ${
        active
          ? 'bg-blue-50 text-blue-700 font-medium'
          : 'text-gray-600 hover:bg-gray-100'
      }`}
    >
      {children}
    </button>
  )
}

export default App

